function addHeroLogo(){let e=document.getElementById("hero");if(!e)return;let t=document.createElement("div"),o=document.createElement("img");o.setAttribute("alt","Logo"),o.setAttribute("src","https://pages.git.generalassemb.ly/modular-curriculum-all-courses/universal-resources-internal/static/v2/assets/hero-logo.png"),t.appendChild(o),document.getElementById("hero").prepend(t)}function addCodeBlockHighlighting(){hljs.highlightAll()}function attachFilePathsToCodeBlocks(){let e=document.querySelectorAll("p");e.forEach(function(e){e.nextElementSibling?.nodeName==="PRE"&&1===e.childNodes.length&&e.childNodes[0]?.nodeName==="CODE"&&(e.classList.add("collapse"),e.childNodes[0].classList.add("codeblock-filepath"))})}function setLinkAttrs(){let e=document.querySelectorAll("a");e.forEach(e=>{let t=e.getAttribute("href");t.startsWith("/")||e.setAttribute("target","_blank")})}function addAnchors(){anchors.add("h2:not(.no-anchor), h3:not(.no-anchor), h4:not(.no-anchor), h5:not(.no-anchor)")}document.addEventListener("DOMContentLoaded",function(e){addHeroLogo(),addCodeBlockHighlighting(),attachFilePathsToCodeBlocks(),setLinkAttrs(),addAnchors()});